import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("Claim Office", () => {
  it.todo("quote: empty item list → premium 5 G (only processing fee)");
  it.todo("quote: single sword → premium 115 G (100 base + 10 first insurance + 5 fee)");
  it.todo("quote: single amulet → premium 71 G (60 base + 6 first insurance + 5 fee)");
  it.todo("quote: single staff → premium 93 G (80 base + 8 first insurance + 5 fee)");
  it.todo("quote: single potion → premium 49 G (40 base + 4 first insurance + 5 fee)");
  it.todo("quote: single rune → premium 33 G (25 base + 2.5 first insurance + 5 fee = 32.5 rounded up)");

  it.todo("quote: 2 runes → premium 60 G (50 base + 5 first insurance + 5 fee)");
  it.todo("quote: 3 runes (block of exactly 3) → premium 71 G (60 base + 6 first insurance + 5 fee)");
  it.todo("quote: 4 runes (no block, requires exactly 3) → premium 115 G (100 base + 10 first insurance + 5 fee)");
  it.todo("quote: 7 runes → premium 198 G (175 base + 17.5 first insurance + 5 fee = 197.5 rounded up)");
  it.todo("quote: 2 runes + 1 moonstone (different types, no block) → premium 88 G (75 base + 7.5 first insurance + 5 fee = 87.5 rounded up)");
  it.todo("quote: 3 runes + 3 moonstones (two separate blocks) → premium 137 G (120 base + 12 first insurance + 5 fee)");

  it.todo("quote: cursed sword (newcomer, 0 years) → premium 165 G (100 base + 50 curse + 10 first insurance + 5 fee)");
  it.todo("quote: cursed sword + plain amulet (modifier scope) → premium 231 G (160 policy base + 50 curse on sword only + 16 first insurance + 5 fee)");
  it.todo("quote: sword enchantment 5 + cursed (both surcharges) → premium 195 G (100 base + 50 curse + 30 high enchant + 10 first insurance + 5 fee)");
  it.todo("quote: sword enchantment 5 not cursed (high enchant only) → premium 145 G (100 base + 30 high enchant + 10 first insurance + 5 fee)");
  it.todo("quote: sword enchantment 4 + cursed (curse only, no high enchant) → premium 165 G (100 base + 50 curse + 10 first insurance + 5 fee)");

  it.todo("quote: loyalty discount (exactly 2 years, single sword) → premium 95 G (100 base + 10 first insurance - 20 loyalty + 5 fee)");
  it.todo("quote: follow-up contract (2nd quote step, 0 years, single sword) → premium 100 G (100 base + 10 first insurance - 15 follow-up + 5 fee)");
  it.todo("quote: long-standing 2nd contract (3 years, cursed sword enchantment 7) → premium 160 G (100 + 50 curse + 30 high enchant - 20 loyalty + 10 first insurance - 15 follow-up + 5 fee)");

  it.todo("claim: regular sword (steel, enchantment 3), damage 500 → payout 400, remainingCap 1600");
  it.todo("claim: rune, damage 200 → payout 100, remainingCap 400");

  it.todo("claim: dragon attack damages sword (500) and amulet (300) → payout 600 (100 G deductible per damaged item), remainingCap 2600");

  it.todo("claim: dragon sword enchantment 9, damage 1000 → payout 400 (50% high enchant wins over dragon, then -100 deductible), remainingCap 1600");
  it.todo("claim: dragon sword enchantment 5, damage 800 → payout 700 (dragon full reimbursement, then -100 deductible), remainingCap 1300");
  it.todo("claim: steel sword enchantment 9, damage 1000 → payout 400 (50% high enchant, then -100 deductible), remainingCap 1600");
  it.todo("claim: dragon sword enchantment 8, damage 1000 → payout 400 (high enchant threshold at 8, 50% then -100 deductible), remainingCap 1600");

  it.todo("claim: two swords insured, two damages (500 each) → payout 800 (per-item deductible), remainingCap 3200");

  it.todo("claim: sword + amulet → insurance sum 1600, cap 3200; damage 200 to sword → payout 100, remainingCap 3100");
  it.todo("claim: cursed sword → cap 2000 based on unmodified insurance value; damage 500 → payout 400, remainingCap 1600");
  it.todo("claim: sword + 3 runes (block) → insurance sum 1750, cap 3500; damage 300 to sword → payout 200, remainingCap 3300");

  it.todo("claim: successive claims on sword (cap 2000); first damage 1500 → payout 1400, remainingCap 600; second damage 1500 → payout 600, remainingCap 0");

  it.todo("claim: payout rounding down — sword enchantment 8, damage 901 → 350.5 rounded down to 350, remainingCap 1650");

  it.todo("error: quote with unknown item type 'broomstick' → throws error");
  it.todo("error: claim damages item not in policy (amulet when only sword insured) → throws error");
  it.todo("error: claim with negative damage amount (-200) → throws error");
  it.todo("error: claim with more sword damage entries than swords insured → throws error");
});

export type QuoteItem = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type QuoteStep = {
  op: "quote";
  items: QuoteItem[];
};

export type ClaimStep = {
  op: "claim";
  policy: number;
  incident: {
    cause: string;
    damages: { itemType: string; amount: number }[];
  };
};

export type Step = QuoteStep | ClaimStep;

export type ScenarioInput = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type QuoteResult = { premium: number };
export type ClaimResult = { payout: number; remainingCap: number };
export type StepResult = QuoteResult | ClaimResult;

export type ScenarioOutput = {
  results: StepResult[];
};

export function processScenario(_input: ScenarioInput): ScenarioOutput {
  return { results: [] };
}

